1	import React from "react";
2	import ReactDOM from "react-dom/client";
3	import { RouterProvider } from "@tanstack/react-router";
4	import { createHashHistory, createBrowserHistory } from "@tanstack/react-router";
5	
6	import "@xterm/xterm/css/xterm.css";
7	import "./index.css";
8	
9	import { isElectron } from "./env";
10	import { getRouter } from "./router";
11	import { APP_DISPLAY_NAME } from "./branding";
12	
13	const history = isElectron ? createHashHistory() : createBrowserHistory();
14	
15	const router = getRouter(history);
16	
17	document.title = APP_DISPLAY_NAME;
18	
19	ReactDOM.createRoot(document.getElementById("root") as HTMLElement).render(
20	  <React.StrictMode>
21	    <RouterProvider router={router} />
22	  </React.StrictMode>,
23	);
