86	export function useTheme() {
87	  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
88	  const theme = snapshot.theme;
89	
90	  const resolvedTheme: "light" | "dark" =
91	    theme === "system" ? (snapshot.systemDark ? "dark" : "light") : theme;
92	
93	  const setTheme = useCallback((next: Theme) => {
94	    localStorage.setItem(STORAGE_KEY, next);
95	    applyTheme(next, true);
96	    emitChange();
97	  }, []);
98	
99	  // Keep DOM in sync on mount/change
100	  useEffect(() => {
101	    applyTheme(theme);
102	  }, [theme]);
103	
104	  return { theme, setTheme, resolvedTheme } as const;
105	}
