      statusBar: "#161b22",
      statusBarForeground: "#8b949e",
    },
  },
} as const;

/** All built-in themes as an ordered array (light first). */
export const APP_THEME_LIST: readonly AppTheme[] = [
  APP_THEMES["t3-light"],
  APP_THEMES["t3-dark"],
  APP_THEMES["t3-midnight"],
];

/** Resolve a `ColorThemeSelection` to a concrete `AppTheme` given the OS dark preference. */
export function resolveColorTheme(
  selection: ColorThemeSelection,
  systemIsDark: boolean,
): AppTheme {
  if (selection === "system") {
    return APP_THEMES[systemIsDark ? "t3-dark" : "t3-light"];
  }
  return APP_THEMES[selection];
}

/** Map a `ColorThemeSelection` to the `"light" | "dark"` mode for `useTheme` back-compat. */
export function colorThemeToMode(
  selection: ColorThemeSelection,
  systemIsDark: boolean,
): "light" | "dark" | "system" {
  if (selection === "system") return "system";
  return APP_THEMES[selection].isDark ? "dark" : "light";
}

