import { useCallback, useSyncExternalStore } from "react";
import {
  APP_THEME_LIST,
  APP_THEMES,
  type AppTheme,
  type AppThemeId,
  type ColorThemeSelection,
  colorThemeToMode,
  resolveColorTheme,
} from "@t3tools/shared/theme";

const COLOR_THEME_KEY = "t3code:color-theme";
const THEME_MODE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

// ─── Listeners ───────────────────────────────────────────────────────────────

let listeners: Array<() => void> = [];

function emitChange(): void {
  for (const listener of listeners) listener();
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredSelection(): ColorThemeSelection {
  const raw = localStorage.getItem(COLOR_THEME_KEY);
  if (raw === "system") return "system";
  if (raw && raw in APP_THEMES) return raw as AppThemeId;

  // Migration: map an existing t3code:theme value to a colour theme
  const legacy = localStorage.getItem(THEME_MODE_KEY);
  if (legacy === "dark") return "t3-dark";
  if (legacy === "light") return "t3-light";
  return "system";
}

/** Write CSS custom properties onto <html> as inline styles. */
function applyCssVars(theme: AppTheme): void {
  const el = document.documentElement;
  const c = theme.colors;
  el.style.setProperty("--sidebar-background", c.sidebar);
  el.style.setProperty("--editor-background", c.editor);
  el.style.setProperty("--terminal-background", c.terminal);
  el.style.setProperty("--status-bar-background", c.statusBar);
  el.style.setProperty("--status-bar-foreground", c.statusBarForeground);
}

function applyColorTheme(selection: ColorThemeSelection, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const resolved = resolveColorTheme(selection, getSystemDark());
  document.documentElement.classList.toggle("dark", resolved.isDark);
  applyCssVars(resolved);

  if (suppressTransitions) {
    // Force reflow before removing the suppression class
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// ─── Module-load side-effect: apply before first paint ───────────────────────

applyColorTheme(getStoredSelection());

// ─── useSyncExternalStore plumbing ───────────────────────────────────────────

type ColorThemeSnapshot = {
  selection: ColorThemeSelection;
  systemDark: boolean;
};

let lastSnapshot: ColorThemeSnapshot | null = null;

function getSnapshot(): ColorThemeSnapshot {
  const selection = getStoredSelection();
  const systemDark = selection === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.selection === selection &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { selection, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const mq = window.matchMedia(MEDIA_QUERY);
  const handleMedia = (): void => {
    if (getStoredSelection() === "system") applyColorTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleMedia);

  const handleStorage = (e: StorageEvent): void => {
    if (e.key === COLOR_THEME_KEY || e.key === THEME_MODE_KEY) {
      applyColorTheme(getStoredSelection(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleMedia);
    window.removeEventListener("storage", handleStorage);
  };
}

// ─── Hook ────────────────────────────────────────────────────────────────────

export function useColorTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { selection } = snapshot;

  const resolvedTheme = resolveColorTheme(selection, snapshot.systemDark);

  const setColorTheme = useCallback((next: ColorThemeSelection): void => {
    // Persist the colour-theme selection
    localStorage.setItem(COLOR_THEME_KEY, next);

    // Keep the legacy theme-mode key in sync so useTheme() consumers still work
    const mode = colorThemeToMode(next, getSystemDark());
    localStorage.setItem(THEME_MODE_KEY, mode);

    applyColorTheme(next, true);
    emitChange();
  }, []);

  return { selection, resolvedTheme, setColorTheme, themes: APP_THEME_LIST } as const;
}

export type { ColorThemeSelection, AppThemeId };

