import { type AppTheme, APP_THEME_LIST } from "@t3tools/shared/theme";
import { useColorTheme, type ColorThemeSelection } from "../hooks/useColorTheme";

// ─── Colour swatch ────────────────────────────────────────────────────────────

interface SwatchStripProps {
  theme: AppTheme;
}

function SwatchStrip({ theme }: SwatchStripProps) {
  const { colors } = theme;
  return (
    <span
      className="flex h-4 w-12 overflow-hidden rounded-sm border border-black/10"
      aria-hidden="true"
    >
      <span className="flex-1" style={{ background: colors.sidebar }} />
      <span className="flex-1" style={{ background: colors.editor }} />
      <span className="flex-[0.5]" style={{ background: colors.accent }} />
    </span>
  );
}

// ─── System option ────────────────────────────────────────────────────────────

interface SystemSwatchProps {
  selected: boolean;
}

function SystemSwatch({ selected }: SystemSwatchProps) {
  // Half-light / half-dark split to communicate "follow OS"
  return (
    <span
      className="flex h-4 w-12 overflow-hidden rounded-sm border border-black/10"
      aria-hidden="true"
    >
      <span className="flex-1" style={{ background: "#ffffff" }} />
      <span className="flex-1" style={{ background: "#0f1014" }} />
    </span>
  );
}

// ─── Single option button ─────────────────────────────────────────────────────

interface ThemeOptionProps {
  value: ColorThemeSelection;
  label: string;
  description: string;
  selected: boolean;
  swatch: React.ReactNode;
  onSelect: (value: ColorThemeSelection) => void;
}

function ThemeOption({ value, label, description, selected, swatch, onSelect }: ThemeOptionProps) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={`flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent"
      }`}
      onClick={() => onSelect(value)}
    >
      <span className="flex flex-col gap-0.5">
        <span className="text-sm font-medium">{label}</span>
        <span className="text-xs">{description}</span>
      </span>
      <span className="flex items-center gap-2">
        {swatch}
        {selected ? (
          <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Selected
          </span>
        ) : null}
      </span>
    </button>
  );
}

// ─── ThemeSelector ────────────────────────────────────────────────────────────

const SYSTEM_DESCRIPTION = "Follow your OS appearance setting.";

function themeDescription(theme: AppTheme): string {
  switch (theme.id) {
    case "t3-light":
      return "Always use the light theme.";
    case "t3-dark":
      return "Always use the dark theme.";
    case "t3-midnight":
      return "Deep blue-black theme for late-night sessions.";
    default:
      return "";
  }
}

export function ThemeSelector() {
  const { selection, resolvedTheme, setColorTheme } = useColorTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
      {/* System option */}
      <ThemeOption
        value="system"
        label="System"
        description={SYSTEM_DESCRIPTION}
        selected={selection === "system"}
        swatch={<SystemSwatch selected={selection === "system"} />}
        onSelect={setColorTheme}
      />

      {/* Built-in themes */}
      {APP_THEME_LIST.map((theme) => (
        <ThemeOption
          key={theme.id}
          value={theme.id}
          label={theme.label}
          description={themeDescription(theme)}
          selected={selection === theme.id}
          swatch={<SwatchStrip theme={theme} />}
          onSelect={setColorTheme}
        />
      ))}

      <p className="pt-2 text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">{resolvedTheme.label}</span>
      </p>
    </div>
  );
}

