export type AppThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/** The value stored in localStorage — one of the built-in ids or "system". */
export type ColorThemeSelection = AppThemeId | "system";

export interface AppThemeColors {
  /** Main app background */
  background: string;
  /** Primary text colour */
  foreground: string;
  /** Interactive accent / primary colour */
  accent: string;
  /** Sidebar / navigation panel background */
  sidebar: string;
  /** Editor / content area background */
  editor: string;
  /** Terminal panel background */
  terminal: string;
  /** Status-bar strip background */
  statusBar: string;
  /** Status-bar strip foreground (text/icons) */
  statusBarForeground: string;
}

export interface AppTheme {
  id: AppThemeId;
  label: string;
  isDark: boolean;
  colors: AppThemeColors;
}

export const APP_THEMES: Record<AppThemeId, AppTheme> = {
  "t3-light": {
    id: "t3-light",
    label: "T3 Light",
    isDark: false,
    colors: {
      background: "#ffffff",
      foreground: "#1c1c1e",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "#f5f5f7",
      editor: "#ffffff",
      terminal: "#f0f0f2",
      statusBar: "#e8e8eb",
      statusBarForeground: "#4a4a52",
    },
  },
  "t3-dark": {
    id: "t3-dark",
    label: "T3 Dark",
    isDark: true,
    colors: {
      background: "#0f1014",
      foreground: "#e8e8ec",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "#0b0c10",
      editor: "#0f1014",
      terminal: "#09090c",
      statusBar: "#0b0c10",
      statusBarForeground: "#9898a8",
    },
  },
  "t3-midnight": {
    id: "t3-midnight",
    label: "T3 Midnight",
    isDark: true,
    colors: {
      background: "#0b0d14",
      foreground: "#c9d1d9",
      accent: "#58a6ff",
      sidebar: "#0d1117",
      editor: "#0b0d14",
      terminal: "#020408",
      statusBar: "#161b22",
      statusBarForeground: "#8b949e",
    },
  },
} as const;

/** All built-in themes as an ordered array (light first). */
export const APP_THEME_LIST: readonly AppTheme[] = [
  APP_THEMES["t3-light"],
  APP_THEMES["t3-dark"],
  APP_THEMES["t3-midnight"],
];

/** Resolve a `ColorThemeSelection` to a concrete `AppTheme` given the OS dark preference. */
export function resolveColorTheme(
  selection: ColorThemeSelection,
  systemIsDark: boolean,
): AppTheme {
  if (selection === "system") {
    return APP_THEMES[systemIsDark ? "t3-dark" : "t3-light"];
  }
  return APP_THEMES[selection];
}

/** Map a `ColorThemeSelection` to the `"light" | "dark"` mode for `useTheme` back-compat. */
export function colorThemeToMode(
  selection: ColorThemeSelection,
  systemIsDark: boolean,
): "light" | "dark" | "system" {
  if (selection === "system") return "system";
  return APP_THEMES[selection].isDark ? "dark" : "light";
}

