1	import { useCallback, useSyncExternalStore } from "react";
2	import {
3	  APP_THEME_LIST,
4	  APP_THEMES,
5	  type AppTheme,
6	  type AppThemeId,
7	  type ColorThemeSelection,
8	  colorThemeToMode,
9	  resolveColorTheme,
10	} from "@t3tools/shared/theme";
11	
12	const COLOR_THEME_KEY = "t3code:color-theme";
13	const THEME_MODE_KEY = "t3code:theme";
14	const MEDIA_QUERY = "(prefers-color-scheme: dark)";
15	
16	// ─── Listeners ───────────────────────────────────────────────────────────────
17	
18	let listeners: Array<() => void> = [];
19	
20	function emitChange(): void {
21	  for (const listener of listeners) listener();
22	}
23	
24	// ─── Helpers ─────────────────────────────────────────────────────────────────
25	
26	function getSystemDark(): boolean {
27	  return window.matchMedia(MEDIA_QUERY).matches;
28	}
29	
30	function getStoredSelection(): ColorThemeSelection {
31	  const raw = localStorage.getItem(COLOR_THEME_KEY);
32	  if (raw === "system") return "system";
33	  if (raw && raw in APP_THEMES) return raw as AppThemeId;
34	
35	  // Migration: map an existing t3code:theme value to a colour theme
36	  const legacy = localStorage.getItem(THEME_MODE_KEY);
37	  if (legacy === "dark") return "t3-dark";
38	  if (legacy === "light") return "t3-light";
39	  return "system";
40	}
41	
42	/** Write CSS custom properties onto <html> as inline styles. */
43	function applyCssVars(theme: AppTheme): void {
44	  const el = document.documentElement;
45	  const c = theme.colors;
46	  el.style.setProperty("--sidebar-background", c.sidebar);
47	  el.style.setProperty("--editor-background", c.editor);
48	  el.style.setProperty("--terminal-background", c.terminal);
49	  el.style.setProperty("--status-bar-background", c.statusBar);
50	  el.style.setProperty("--status-bar-foreground", c.statusBarForeground);
51	}
52	
53	function applyColorTheme(selection: ColorThemeSelection, suppressTransitions = false): void {
54	  if (suppressTransitions) {
55	    document.documentElement.classList.add("no-transitions");
56	  }
57	
58	  const resolved = resolveColorTheme(selection, getSystemDark());
59	  document.documentElement.classList.toggle("dark", resolved.isDark);
60	  applyCssVars(resolved);
61	
62	  if (suppressTransitions) {
63	    // Force reflow before removing the suppression class
64	    // oxlint-disable-next-line no-unused-expressions
65	    document.documentElement.offsetHeight;
66	    requestAnimationFrame(() => {
67	      document.documentElement.classList.remove("no-transitions");
68	    });
69	  }
70	}
71	
72	// ─── Module-load side-effect: apply before first paint ───────────────────────
73	
74	applyColorTheme(getStoredSelection());
75	
76	// ─── useSyncExternalStore plumbing ───────────────────────────────────────────
77	
78	type ColorThemeSnapshot = {
79	  selection: ColorThemeSelection;
80	  systemDark: boolean;
81	};
82	
83	let lastSnapshot: ColorThemeSnapshot | null = null;
84	
85	function getSnapshot(): ColorThemeSnapshot {
86	  const selection = getStoredSelection();
87	  const systemDark = selection === "system" ? getSystemDark() : false;
88	
89	  if (
90	    lastSnapshot &&
91	    lastSnapshot.selection === selection &&
92	    lastSnapshot.systemDark === systemDark
93	  ) {
94	    return lastSnapshot;
95	  }
96	
97	  lastSnapshot = { selection, systemDark };
98	  return lastSnapshot;
99	}
100	
101	function subscribe(listener: () => void): () => void {
102	  listeners.push(listener);
103	
104	  const mq = window.matchMedia(MEDIA_QUERY);
105	  const handleMedia = (): void => {
106	    if (getStoredSelection() === "system") applyColorTheme("system", true);
107	    emitChange();
108	  };
109	  mq.addEventListener("change", handleMedia);
110	
111	  const handleStorage = (e: StorageEvent): void => {
112	    if (e.key === COLOR_THEME_KEY || e.key === THEME_MODE_KEY) {
113	      applyColorTheme(getStoredSelection(), true);
114	      emitChange();
115	    }
116	  };
117	  window.addEventListener("storage", handleStorage);
118	
119	  return () => {
120	    listeners = listeners.filter((l) => l !== listener);
121	    mq.removeEventListener("change", handleMedia);
122	    window.removeEventListener("storage", handleStorage);
123	  };
124	}
125	
126	// ─── Hook ────────────────────────────────────────────────────────────────────
127	
128	export function useColorTheme() {
129	  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
130	  const { selection } = snapshot;
131	
132	  const resolvedTheme = resolveColorTheme(selection, snapshot.systemDark);
133	
134	  const setColorTheme = useCallback((next: ColorThemeSelection): void => {
135	    // Persist the colour-theme selection
136	    localStorage.setItem(COLOR_THEME_KEY, next);
137	
138	    // Keep the legacy theme-mode key in sync so useTheme() consumers still work
139	    const mode = colorThemeToMode(next, getSystemDark());
140	    localStorage.setItem(THEME_MODE_KEY, mode);
141	
142	    applyColorTheme(next, true);
143	    emitChange();
144	  }, []);
145	
146	  return { selection, resolvedTheme, setColorTheme, themes: APP_THEME_LIST } as const;
147	}
148	
149	export type { ColorThemeSelection, AppThemeId };
150	

